import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{i,n as a,r as o,t as s}from"./chunks/windows-wizard-screenshot.QBlzzreT.js";const c=JSON.parse(`{"title":"在 Windows 上安装 Java","description":"在 Windows 上安装 Java 的逐步指南。","frontmatter":{"title":"在 Windows 上安装 Java","description":"在 Windows 上安装 Java 的逐步指南。","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"zh_cn/1.20.4/players/installing-java/windows.md","filePath":"versions/1.20.4/translated/zh_cn/players/installing-java/windows.md","lastUpdated":1739538073000}`);var l={name:`zh_cn/1.20.4/players/installing-java/windows.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">在 Windows 上安装 Java <a class="header-anchor" href="#h1" aria-label="Permalink to “在 Windows 上安装 Java”">​</a></h1><p>这个指南将会指引您在 Windows 上安装 Java 17。</p><p>Minecraft 启动器附带了自己的 Java 安装，因此这部分只在你想使用 Fabric 的 <code>.jar</code> 安装程序，或者你想使用 Minecraft 服务器的 <code>.jar</code> 时有关。</p><h2 id="_1-检查-java-是否已被安装" tabindex="-1">1. 检查 Java 是否已被安装 <a class="header-anchor" href="#_1-检查-java-是否已被安装" aria-label="Permalink to “1. 检查 Java 是否已被安装”">​</a></h2><p>要检查 Java 是否已安装，你首先必须打开命令提示符。</p><p>你可以通过按下 <kbd>Win</kbd>+<kbd>R</kbd> 并在出现的对话框中输入 <code>cmd.exe</code> 来实现它。</p><p><img src="/assets/players/installing-java/windows-run-dialog.png" alt="Windows运行对话框中的「cmd.exe」" loading="lazy"></p><p>打开命令提示符后，输入 <code>java -version</code> 并按下 <kbd>Enter</kbd> 键。</p><p>如果命令成功运行，你会看到类似这样的内容。 如果命令运行失败，请继续进行下一步。</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="命令提示符中输入了「java -version」" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>要使用较新的 Minecraft (1.19.x 及以上) 版本，你至少需要安装版本 ≥ 17 的 Java。 如果运行该命令后显示 Java 版本低于 17，你需要更新设备上现有 Java。</p></div><h2 id="_2-下载-java-17-安装程序" tabindex="-1">2. 下载 Java 17 安装程序 <a class="header-anchor" href="#_2-下载-java-17-安装程序" aria-label="Permalink to “2. 下载 Java 17 安装程序”">​</a></h2><p>要安装 Java 17，你需要从 <a href="https://adoptium.net/en-GB/temurin/releases/?os=windows&amp;package=jdk&amp;version=17" target="_blank" rel="noreferrer">Adoptium</a> 下载安装程序。</p><p>你需要下载 <code>Windows Installer (.msi)</code> 版本：</p><p><img src="/assets/players/installing-java/windows-download-java.png" alt="Adoptium 下载页面，使用了 Windows 安装程序 (.msi)" loading="lazy"></p><p>如果你有 32 位操作系统，应该选择 <code>x86</code>；如果你有 64 位操作系统，则应该选择 <code>x64</code>。</p><p>现代大多数电脑都运行 64 位操作系统。 如果你不确定，请尝试使用 64 位的下载。</p><h2 id="_3-运行安装程序" tabindex="-1">3. 运行安装程序！ <a class="header-anchor" href="#_3-运行安装程序" aria-label="Permalink to “3. 运行安装程序！”">​</a></h2><p>按照安装程序的步骤安装 Java 17。 当你到达这个页面时，你应该将以下功能设置为「整个功能将安装在本机硬盘上」：</p><ul><li><code>Set JAVA_HOME environment variable</code> - 这将加入到你的PATH中。</li><li><code>JavaSoft (Oracle) registry keys</code></li></ul><p><img src="/assets/players/installing-java/windows-wizard-screenshot.png" alt="Java 17 安装程序，具有「Set JAVA_HOME variable」和「JavaSoft (Oracle) registry keys」" loading="lazy"></p><p>完成后，你可以按 <code>下一步</code> 继续安装。</p><h2 id="_4-检查-java-17-是否已被正确安装" tabindex="-1">4. 检查 Java 17 是否已被正确安装 <a class="header-anchor" href="#_4-检查-java-17-是否已被正确安装" aria-label="Permalink to “4. 检查 Java 17 是否已被正确安装”">​</a></h2><p>安装完成后，您可以打开终端并输入 <code>java -version</code> 来验证 Java 17 是否已安装。</p><p>如果命令成功执行，你可以看到类似前文所示的内容，Java 版本被显示出来：</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="命令提示符中输入了「java -version」" loading="lazy"></p><p>如果遇到任何问题，你可以在 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 频道中寻求帮助。</p>`,27)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};